async function seed() {
  let inserted = 0;
  let skipped = 0;

  for (const post of blogPostSeedData) {
    const { slug, ...data } = post;
    const result = await client.mutation(api.blogPosts.insert, { slug, data: post });
    if (result) {
      inserted++;
      console.log(`✓ ${post.title}`);
    } else {
      skipped++;
      console.log(`— skipped (already exists): ${post.title}`);
    }
  }

  console.log(`\nDone! Inserted: ${inserted}, Skipped: ${skipped}`);
}

seed().catch(console.error);
